    41→/**
    42→ * Check if URL is external (needs import to Cloudinary)
    43→ * Skip Cloudinary URLs (already cloud-hosted)
    44→ */
    45→function isExternalUrl(url: string | null | undefined): boolean {
    46→  if (!url) return false;
    47→  if (!url.startsWith('http://') && !url.startsWith('https://')) return false;
    48→  // Skip Cloudinary URLs (already cloud-hosted, no need to import)
    49→  if (url.includes('res.cloudinary.com')) return false;
    50→  return true;
    51→}
