     1→/**
     2→ * useSupabaseStore - Zustand Store with Supabase Sync
     3→ *
     4→ * Feature: 040-supabase-migration
     5→ * Tasks: T033, T034, T035, T036
     6→ *
     7→ * Provides a zustand store compatible with the existing UI components
     8→ * but backed by Supabase instead of Firebase.
     9→ *
    10→ * Replaces: hooks/useStore.ts (Firebase version)
    11→ */
    12→
    13→'use client';
    14→
    15→import { create } from 'zustand';
    16→import { persist } from 'zustand/middleware';
    17→import { toast } from 'sonner';
    18→import { createClient } from '@/lib/supabase/client';
    19→import {
    20→  gearItemToDbInsert,
    21→  gearItemToDbUpdate,
    22→} from '@/lib/supabase/transformers';
    23→import type { GearItem } from '@/types/gear';
    24→import type { TablesInsert, TablesUpdate } from '@/types/database';
    25→import type { ActivityType, Season } from '@/types/loadout';
    26→
    27→// =============================================================================
    28→// Types
    29→// =============================================================================
    30→
    31→interface LoadoutLocal {
    32→  id: string;
    33→  name: string;
    34→  tripDate: Date | null;
    35→  itemIds: string[];
    36→  description: string | null;
    37→  activityTypes: ActivityType[];
    38→  seasons: Season[];
    39→  itemStates: ItemState[];
    40→  createdAt: Date;
    41→  updatedAt: Date;
    42→}
    43→
    44→interface ItemState {
    45→  itemId: string;
    46→  isWorn: boolean;
    47→  isConsumable: boolean;
    48→}
    49→
    50→interface SyncState {
    51→  status: 'idle' | 'syncing' | 'error';
    52→  error: string | null;
    53→  lastSyncedAt: Date | null;
    54→  pendingOperations: number;
    55→}
    56→
    57→const DEFAULT_SYNC_STATE: SyncState = {
    58→  status: 'idle',
    59→  error: null,
    60→  lastSyncedAt: null,
    61→  pendingOperations: 0,
    62→};
    63→
    64→interface SupabaseStore {
    65→  // State
    66→  items: GearItem[];
    67→  loadouts: LoadoutLocal[];
    68→  userId: string | null;
    69→  _initialized: boolean;
    70→  syncState: SyncState;
    71→
    72→  // User Actions
    73→  setUserId: (userId: string | null) => void;
    74→
    75→  // Item Actions
    76→  addItem: (item: Omit<GearItem, 'id' | 'createdAt' | 'updatedAt'>) => Promise<string>;
    77→  updateItem: (id: string, updates: Partial<GearItem>) => Promise<void>;
    78→  deleteItem: (id: string) => Promise<void>;
    79→
    80→  // Loadout Actions
    81→  createLoadout: (
    82→    name: string,
    83→    tripDate?: Date | null,
    84→    options?: {
    85→      description?: string;
    86→      seasons?: Season[];
    87→      activityTypes?: ActivityType[];
    88→    }
    89→  ) => Promise<string>;
    90→  updateLoadout: (id: string, updates: Partial<LoadoutLocal>) => Promise<void>;
    91→  deleteLoadout: (id: string) => Promise<void>;
    92→  addItemToLoadout: (loadoutId: string, itemId: string) => Promise<void>;
    93→  removeItemFromLoadout: (loadoutId: string, itemId: string) => Promise<void>;
    94→  updateLoadoutMetadata: (id: string, metadata: Partial<LoadoutLocal>) => Promise<void>;
    95→
    96→  // Item State Actions
    97→  setItemWorn: (loadoutId: string, itemId: string, isWorn: boolean) => Promise<void>;
    98→  setItemConsumable: (loadoutId: string, itemId: string, isConsumable: boolean) => Promise<void>;
    99→
   100→  // Sync Actions
   101→  setSyncState: (updates: Partial<SyncState>) => void;
   102→  setRemoteGearItems: (items: GearItem[]) => void;
   103→  setRemoteLoadouts: (loadouts: LoadoutLocal[]) => void;
   104→}
   105→
   106→// =============================================================================
   107→// Store Implementation
   108→// =============================================================================
   109→
   110→export const useSupabaseStore = create<SupabaseStore>()(
   111→  persist(
   112→    (set, get) => ({
   113→      // State
   114→      items: [],
   115→      loadouts: [],
   116→      userId: null,
   117→      _initialized: false,
   118→      syncState: DEFAULT_SYNC_STATE,
   119→
   120→      // User Actions
   121→      setUserId: (userId) => {
   122→        set({ userId });
   123→      },
   124→
   125→      // Item Actions
   126→      addItem: async (item) => {
   127→        const { userId } = get();
   128→        console.log('[SupabaseStore] addItem called, userId:', userId);
   129→        if (!userId) {
   130→          toast.error('Please sign in to add items');
   131→          throw new Error('User not authenticated');
   132→        }
   133→
   134→        const supabase = createClient();
   135→        const id = crypto.randomUUID();
   136→        const now = new Date();
   137→
   138→        // Create optimistic item
   139→        const newItem: GearItem = {
   140→          ...item,
   141→          id,
   142→          createdAt: now,
   143→          updatedAt: now,
   144→        };
   145→
   146→        // Optimistic update
   147→        set((state) => ({
   148→          items: [...state.items, newItem],
   149→          syncState: { ...state.syncState, status: 'syncing', pendingOperations: state.syncState.pendingOperations + 1 },
   150→        }));

