    27→/**
    28→ * Compute averaged priorities across selected activities.
    29→ * Returns neutral values (50) if no activities selected.
    30→ */
    31→export function computeAveragePriorities(
    32→  selectedActivities: ActivityType[]
    33→): ActivityPriorities {
    34→  if (selectedActivities.length === 0) {
    35→    return { weight: 50, comfort: 50, durability: 50, safety: 50 };
    36→  }
    37→
    38→  const totals = selectedActivities.reduce(
    39→    (acc, activity) => {
    40→      const priorities = ACTIVITY_PRIORITY_MATRIX[activity];
    41→      return {
    42→        weight: acc.weight + priorities.weight,
    43→        comfort: acc.comfort + priorities.comfort,
    44→        durability: acc.durability + priorities.durability,
    45→        safety: acc.safety + priorities.safety,
    46→      };
    47→    },
    48→    { weight: 0, comfort: 0, durability: 0, safety: 0 }
    49→  );
    50→
    51→  const count = selectedActivities.length;
    52→  return {
    53→    weight: Math.round(totals.weight / count),
    54→    comfort: Math.round(totals.comfort / count),
    55→    durability: Math.round(totals.durability / count),
    56→    safety: Math.round(totals.safety / count),
    57→  };
    58→}
