    90→  /**
    91→   * Check if an item can be added to the loadout based on available quantity
    92→   * Feature: 013-gear-quantity-tracking
    93→   *
    94→   * For MVP scope: Validates only within current loadout (cross-loadout tracking out of scope)
    95→   *
    96→   * @param itemId - ID of the gear item to check
    97→   * @returns true if item can be added, false otherwise
    98→   */
    99→  const canAddItem = useCallback(
   100→    (itemId: string): boolean => {
   101→      // Get the gear item from inventory
   102→      const gearItem = items.find((item) => item.id === itemId);
   103→      if (!gearItem) {
   104→        toast.error('Item not found in inventory');
   105→        return false;
   106→      }
   107→
   108→      // Check if item is already in loadout
   109→      const isInLoadout = loadout?.itemIds.includes(itemId) ?? false;
   110→
   111→      if (isInLoadout) {
   112→        // Item already in loadout - current system doesn't support quantity increment
   113→        // Show error that all available quantity is already in use
   114→        toast.error('Cannot add more items', {
   115→          description: `This item is already in the loadout. Only ${gearItem.quantity} available in inventory.`,
   116→        });
   117→        return false;
   118→      }
   119→
   120→      // Check if item has quantity > 0 in inventory
   121→      const availableQuantity = gearItem.quantity || 1; // Default to 1 for backward compatibility
   122→
   123→      if (availableQuantity < 1) {
   124→        toast.error('No items available', {
   125→          description: 'This item has no available quantity in inventory.',
   126→        });
   127→        return false;
   128→      }
   129→
   130→      // Item can be added
   131→      return true;
   132→    },
   133→    [items, loadout]
   134→  );
   135→
   136→  return {
   137→    isWorn,
   138→    isConsumable,
   139→    toggleWorn,
   140→    toggleConsumable,
   141→    canAddItem,
   142→  };
