   131→ * Format a weight value with its unit suffix
   132→ *
   133→ * @param value - The weight value
   134→ * @param unit - The weight unit
   135→ * @param precision - Number of decimal places (default: 1)
   136→ * @returns Formatted string like "123.4 g" or "4.3 oz"
   137→ */
   138→export function formatWeight(value: number, unit: WeightUnit, precision: number = 1): string {
   139→  const formatted = value.toFixed(precision);
   140→  return `${formatted} ${unit}`;
   141→}
   142→
   143→/**
   144→ * Format a weight value stored in grams for display in a specific unit
   145→ *
   146→ * @param grams - The weight in grams
   147→ * @param displayUnit - The unit to display in
   148→ * @param precision - Number of decimal places (default: 1)
   149→ * @returns Formatted string like "123.4 g" or "4.3 oz"
   150→ */
   151→export function formatWeightFromGrams(
   152→  grams: number,
   153→  displayUnit: WeightUnit,
   154→  precision: number = 1
   155→): string {
   156→  const value = fromGrams(grams, displayUnit);
   157→  return formatWeight(value, displayUnit, precision);
   158→}
