     1→/**
     2→ * useLoadoutItemState - Hook for managing worn/consumable item states
     3→ *
     4→ * Feature: 007-grand-polish-sprint
     5→ * US4: Advanced Weight Calculations
     6→ * Provides functions to toggle worn and consumable states for items in a loadout
     7→ *
     8→ * Feature: 013-gear-quantity-tracking
     9→ * Phase 5: Loadout Quantity Validation
    10→ * Provides quantity validation before adding items to prevent over-allocation
    11→ */
    12→
    13→'use client';
    14→
    15→import { useCallback } from 'react';
    16→import { toast } from 'sonner';
    17→import { useTranslations } from 'next-intl';
    18→import { useStore } from '@/hooks/useSupabaseStore';
    19→
    20→// =============================================================================
    21→// Types
    22→// =============================================================================
    23→
    24→interface UseLoadoutItemStateReturn {
    25→  /** Get worn state for an item */
    26→  isWorn: (itemId: string) => boolean;
    27→  /** Get consumable state for an item */
    28→  isConsumable: (itemId: string) => boolean;
    29→  /** Toggle worn state for an item */
    30→  toggleWorn: (itemId: string) => Promise<void>;
    31→  /** Toggle consumable state for an item */
    32→  toggleConsumable: (itemId: string) => Promise<void>;
    33→  /** Check if item can be added based on available quantity (Feature: 013) */
    34→  canAddItem: (itemId: string) => boolean;
    35→}
    36→
    37→// =============================================================================
    38→// Hook Implementation
    39→// =============================================================================
    40→
    41→export function useLoadoutItemState(loadoutId: string): UseLoadoutItemStateReturn {
    42→  const t = useTranslations('Loadouts.errors');
    43→  const loadout = useStore((state) =>
    44→    state.loadouts.find((l) => l.id === loadoutId)
    45→  );
    46→  const items = useStore((state) => state.items);
    47→  const setItemWorn = useStore((state) => state.setItemWorn);
    48→  const setItemConsumable = useStore((state) => state.setItemConsumable);
    49→
    50→  const isWorn = useCallback(
    51→    (itemId: string): boolean => {
    52→      const state = loadout?.itemStates.find((s) => s.itemId === itemId);
    53→      return state?.isWorn ?? false;
    54→    },
    55→    [loadout?.itemStates]
    56→  );
    57→
    58→  const isConsumable = useCallback(
    59→    (itemId: string): boolean => {
    60→      const state = loadout?.itemStates.find((s) => s.itemId === itemId);
    61→      return state?.isConsumable ?? false;
    62→    },
    63→    [loadout?.itemStates]
    64→  );
    65→
    66→  const toggleWorn = useCallback(
    67→    async (itemId: string) => {
    68→      const currentState = isWorn(itemId);
    69→      try {
    70→        await setItemWorn(loadoutId, itemId, !currentState);
    71→      } catch (error) {
    72→        // Error toast is already shown by the store
    73→        console.error('[LoadoutItemState] Failed to toggle worn state:', error);
    74→      }
    75→    },
    76→    [loadoutId, isWorn, setItemWorn]
    77→  );
    78→
    79→  const toggleConsumable = useCallback(
    80→    async (itemId: string) => {
    81→      const currentState = isConsumable(itemId);
    82→      try {
    83→        await setItemConsumable(loadoutId, itemId, !currentState);
    84→      } catch (error) {
    85→        // Error toast is already shown by the store
    86→        console.error('[LoadoutItemState] Failed to toggle consumable state:', error);
    87→      }
    88→    },
    89→    [loadoutId, isConsumable, setItemConsumable]
    90→  );
    91→
    92→  /**
    93→   * Check if an item can be added to the loadout based on available quantity
    94→   * Feature: 013-gear-quantity-tracking
    95→   *
    96→   * For MVP scope: Validates only within current loadout (cross-loadout tracking out of scope)
    97→   *
    98→   * @param itemId - ID of the gear item to check
    99→   * @returns true if item can be added, false otherwise
   100→   */
   101→  const canAddItem = useCallback(
   102→    (itemId: string): boolean => {
   103→      // Get the gear item from inventory
   104→      const gearItem = items.find((item) => item.id === itemId);
   105→      if (!gearItem) {
   106→        toast.error(t('itemNotFound'));
   107→        return false;
   108→      }
   109→
   110→      // Check if item is already in loadout
   111→      const isInLoadout = loadout?.itemIds.includes(itemId) ?? false;
   112→
   113→      if (isInLoadout) {
   114→        // Item already in loadout - current system doesn't support quantity increment
   115→        // Show error that all available quantity is already in use
   116→        toast.error(t('quantityExceeded'), {
   117→          description: t('quantityExceededDescription', { available: gearItem.quantity }),
   118→        });
   119→        return false;
   120→      }
   121→
   122→      // Check if item has quantity > 0 in inventory
   123→      const availableQuantity = gearItem.quantity || 1; // Default to 1 for backward compatibility
   124→
   125→      if (availableQuantity < 1) {
   126→        toast.error(t('noQuantityAvailable'), {
   127→          description: t('noQuantityAvailableDescription'),
   128→        });
   129→        return false;
   130→      }
   131→
   132→      // Item can be added
   133→      return true;
   134→    },
   135→    [items, loadout, t]
   136→  );
   137→
   138→  return {
   139→    isWorn,
   140→    isConsumable,
   141→    toggleWorn,
   142→    toggleConsumable,
   143→    canAddItem,
   144→  };
   145→}
